import React, { useState } from 'react';

const ProductList: React.FC = () => {
  const [products] = useState([
    { id: 1, name: 'Apples', image: 'https://images.unsplash.com/photo-1567306226416-28f0efdc88ce?w=400' },
    { id: 2, name: 'Carrots', image: 'https://images.unsplash.com/photo-1582515073490-dc7bfb9e8f24?w=400' },
    { id: 3, name: 'Bananas', image: 'https://images.unsplash.com/photo-1574226516831-e1dff420e8f8?w=400' }
  ]);

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <h2 className="text-2xl font-bold text-gray-800 mb-6">Our Products</h2>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {products.map(product => (
          <div key={product.id} className="bg-white p-4 rounded-xl shadow-md">
            <img src={product.image} alt={product.name} className="w-full h-40 object-cover rounded-xl" />
            <h3 className="text-lg font-semibold text-gray-700 mt-4">{product.name}</h3>
            <button className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition mt-2">Buy Now</button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ProductList;
